import React, { useState } from 'react';
import api from '../utils/api';

const inp: React.CSSProperties = { width: '100%', padding: '10px 14px', border: '2px solid #e8e0d0', borderRadius: 10, fontSize: 14, fontFamily: 'inherit', outline: 'none', color: '#1a1a2e', background: '#fff' };
const lbl: React.CSSProperties = { display: 'block', fontSize: 12, fontWeight: 600, color: '#6b7280', marginBottom: 6 };

export default function CreateAssistant() {
  const [form, setForm] = useState({ name: '', email: '', password: '', confirm_password: '', mobile: '', gender: '', address: '' });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const set = (k: string, v: string) => setForm(f => ({ ...f, [k]: v }));

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(''); setSuccess('');
    if (form.password !== form.confirm_password) { setError('Passwords do not match!'); return; }
    if (form.password.length < 6) { setError('Password must be at least 6 characters!'); return; }
    setLoading(true);
    try {
      await api.post('/auth/create-assistant', form);
      setSuccess('✅ Library Assistant account created successfully!');
      setForm({ name: '', email: '', password: '', confirm_password: '', mobile: '', gender: '', address: '' });
    } catch (e: any) {
      setError(e.response?.data?.message || 'Failed to create account');
    } finally { setLoading(false); }
  };

  return (
    <div className="page-enter" style={{ padding: 32 }}>
      <div style={{ marginBottom: 28 }}>
        <h1 style={{ fontFamily: "'Playfair Display',serif", fontSize: 28, fontWeight: 700 }}>Create Library Assistant</h1>
        <p style={{ color: '#9ca3af', fontSize: 13, marginTop: 4 }}>Create a new Library Assistant account</p>
      </div>

      <div style={{ maxWidth: 560, background: '#fff', borderRadius: 20, padding: 32, border: '1px solid #e8e0d0' }}>
        {/* Header */}
        <div style={{ display: 'flex', alignItems: 'center', gap: 14, marginBottom: 24, padding: 16, background: '#f5f0e8', borderRadius: 12 }}>
          <div style={{ width: 48, height: 48, background: '#1a1a2e', borderRadius: 12, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 22 }}>📋</div>
          <div>
            <div style={{ fontSize: 14, fontWeight: 700, color: '#1a1a2e' }}>Library Assistant Account</div>
            <div style={{ fontSize: 12, color: '#9ca3af', marginTop: 2 }}>Can issue/return books and manage members</div>
          </div>
        </div>

        {error && <div style={{ background: '#fee2e2', color: '#dc2626', padding: '12px 16px', borderRadius: 10, fontSize: 13, marginBottom: 16 }}>{error}</div>}
        {success && <div style={{ background: '#d1fae5', color: '#059669', padding: '12px 16px', borderRadius: 10, fontSize: 13, marginBottom: 16 }}>{success}</div>}

        <form onSubmit={handleSubmit}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 }}>
            <div style={{ gridColumn: '1/-1' }}>
              <label style={lbl}>Full Name *</label>
              <input style={inp} value={form.name} onChange={e => set('name', e.target.value)} placeholder="Assistant's full name" required />
            </div>

            <div style={{ gridColumn: '1/-1' }}>
              <label style={lbl}>Email Address *</label>
              <input style={inp} type="email" value={form.email} onChange={e => set('email', e.target.value.toLowerCase())} placeholder="assistant@library.com" required />
            </div>

            <div>
              <label style={lbl}>Password *</label>
              <input style={inp} type="password" value={form.password} onChange={e => set('password', e.target.value)} placeholder="Min 6 characters" required />
            </div>

            <div>
              <label style={lbl}>Confirm Password *</label>
              <input style={inp} type="password" value={form.confirm_password} onChange={e => set('confirm_password', e.target.value)} placeholder="Repeat password" required />
            </div>

            <div>
              <label style={lbl}>Mobile</label>
              <input style={inp} value={form.mobile} onChange={e => set('mobile', e.target.value)} placeholder="01XXXXXXXXX" />
            </div>

            <div>
              <label style={lbl}>Gender</label>
              <select style={inp} value={form.gender} onChange={e => set('gender', e.target.value)}>
                <option value="">Select gender</option>
                <option value="male">Male</option>
                <option value="female">Female</option>
                <option value="other">Other</option>
              </select>
            </div>

            <div style={{ gridColumn: '1/-1' }}>
              <label style={lbl}>Address</label>
              <textarea style={{ ...inp, minHeight: 70, resize: 'vertical' }} value={form.address} onChange={e => set('address', e.target.value)} placeholder="Address (optional)" />
            </div>
          </div>

          {/* Permissions Info */}
          <div style={{ margin: '20px 0', background: '#f5f0e8', borderRadius: 12, padding: 16 }}>
            <div style={{ fontSize: 12, fontWeight: 700, color: '#1a1a2e', marginBottom: 10 }}>Library Assistant Permissions:</div>
            <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 6 }}>
              {[
                ['✅', 'Issue & return books'],
                ['✅', 'Approve borrow requests'],
                ['✅', 'Manage members'],
                ['✅', 'Add & edit books'],
                ['❌', 'Delete books'],
                ['❌', 'Delete members'],
                ['❌', 'Create assistants'],
                ['❌', 'System settings'],
              ].map(([icon, text]) => (
                <div key={text} style={{ fontSize: 12, color: '#6b7280', display: 'flex', alignItems: 'center', gap: 6 }}>
                  <span>{icon}</span>{text}
                </div>
              ))}
            </div>
          </div>

          <button type="submit" disabled={loading}
            style={{ width: '100%', padding: 13, background: '#1a1a2e', color: '#fff', border: 'none', borderRadius: 12, fontSize: 14, fontWeight: 600, cursor: 'pointer', fontFamily: 'inherit', opacity: loading ? 0.7 : 1 }}>
            {loading ? 'Creating...' : '+ Create Library Assistant Account'}
          </button>
        </form>
      </div>
    </div>
  );
}
